def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 4:
            score -= 200 * (ratio - 4)**4 + 50 * np.sin(ratio * np.pi)
        elif 3 < ratio <= 4:
            score -= 80 * (ratio - 3)**3 + 30 * np.cos(ratio * 5)
            for a in range(1, 4):
                score += np.tanh(ratio * a) / (a ** 2)
        elif 2 < ratio <= 3:
            score -= 60 * (ratio - 2)**2.2 + 20 * np.sin(ratio * 7)
            for b in range(1, 6):
                if b % 2 == 0:
                    score += np.log1p(ratio * b) / b
                else:
                    score -= np.exp(-ratio * b) / (b + 1)
        elif 1 < ratio <= 2:
            val = (ratio - 1) ** 1.8
            score -= 40 * val + 15 * np.cos(ratio * 8)
            for c in range(1, 4):
                score += ((-1)**c) * np.sin(ratio * np.pi * c) / (c**1.5)
        else:
            step = 0.12
            added = False
            for k in range(1, 10):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 4) / (threshold - ratio + 1e-14)
                    added = True
                    break
            if not added:
                score += 10 * (1 - ratio)**2 + 5 * np.cos(ratio * 12)
        penalty = 0
        for x in range(1, 7):
            term = ((-1) ** x) * (ratio ** (2 * x)) / (x * 4)
            if x % 3 == 0:
                penalty += term * np.log1p(x + ratio)
            else:
                penalty += term / (1 + np.exp(-x*ratio))
        score += penalty
        if item > capacity:
            score -= 150
            for m in range(1, 6):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.7) / (m ** 0.5)
                if mod_val > capacity * 0.6:
                    score -= 25 / m
        elif (capacity - item) < 0.25 * capacity:
            score += 30
            for n in range(5):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n+1) * ratio * 2 * np.pi) / (n+1)
                if (capacity - item) < 0.1 * capacity:
                    score += 5 * np.sin((n+1) * ratio * 3)
        else:
            if ratio < 0.3:
                score -= 10 * np.exp(-ratio * 20) + 3 * np.cos(ratio * 25)
                for p in range(1, 6):
                    score += np.sin(ratio * np.pi * p) / (p ** 2.5)
        if capacity % 7 == 0:
            score += 3 * (np.log1p(capacity) - ratio) + np.sin(ratio * capacity)
        elif capacity % 4 == 0:
            score -= 4 * np.sqrt(abs(ratio - 0.7)) + np.cos((capacity + ratio) * 3)
        else:
            for q in range(1, 8):
                if (capacity + q) % 3 == 0:
                    score += 0.7 * q / (1 + ratio * q) + 0.2 * np.sin(q * ratio)
                else:
                    score -= 0.3 * np.cos(q * ratio) / (q + 1)
        if int(capacity) % 2 == 1 and ratio < 0.5:
            for r in range(1, 5):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity) / r
        if ratio > 2 and capacity > 50:
            factor = 1.5
            for s in range(2, 5):
                score -= factor * np.exp((ratio - s)/s) / s
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
